import React, { useEffect, useState, useCallback } from "react";
import { imagesByProject } from "../utils/assorted";
import '../styles/VerticalCarouselWall.scss';

type ProjectKey = 'banner' | 'aiguire' | 'frontrow' | 'pause' | 'qohoo' | 'skylark' | 'vdoAi' | 'vector';

interface HorizontalCarouselWallProps {
  projects: ProjectKey[];
  direction?: 'left' | 'right';
  speed?: number;
}

const HorizontalCarouselWall: React.FC<HorizontalCarouselWallProps> = ({
  projects,
  direction = 'left',
  speed = 0.9
}) => {
  const normalSpeed = speed;
  const slowSpeed = speed * 0.2;

  const getProjectImages = (projectKeys: ProjectKey[]): string[] => {
    const images = projectKeys.flatMap(project => 
      Object.values(imagesByProject[project])
    );
    // Duplicate images for seamless scrolling
    return [...images, ...images];
  };

  const [images] = useState(() => getProjectImages(projects));
  const [position, setPosition] = useState(direction === 'left' ? 0 : -100);
  const [isHovered, setIsHovered] = useState(false);

  const animate = useCallback(() => {
    setPosition((prev) => {
      const directionMultiplier = direction === 'left' ? -1 : 1;
      const currentSpeed = isHovered ? slowSpeed : normalSpeed;
      let newPos = prev + currentSpeed * directionMultiplier;

      // Reset position when reaching boundaries
      const threshold = 100;
      if (directionMultiplier === -1 && newPos <= -threshold) {
        newPos = 0;
      } else if (directionMultiplier === 1 && newPos >= 0) {
        newPos = -threshold;
      }

      return newPos;
    });
  }, [direction, isHovered, slowSpeed, normalSpeed]);

  useEffect(() => {
    const intervalId = setInterval(animate, 16);
    return () => clearInterval(intervalId);
  }, [animate]);

  return (
    <div 
      className="carousel"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className="carousel-rows">
        <div className="carousel-row">
          <div
            className="row-content"
            style={{
              transform: `translateX(${position}%)`,
            }}
          >
            {images.map((imgSrc, index) => (
              <div
                key={`original-${index}`}
                className="image-wrapper"
                style={{
                  transform: `translateY(${index % 2 === 0 ? '0px' : '0px'})`,
                }}
              >
                <img src={imgSrc} alt={`Carousel image ${index + 1}`} />
              </div>
            ))}
          </div>
        </div>
      </div>
      <div className="gradient gradient--left" />
      <div className="gradient gradient--right" />
    </div>
  );
};

export default HorizontalCarouselWall;

import React, { useState, useEffect, useMemo } from "react";
import "../styles/ProjectCard.scss";
import Buttons from "./Buttons";

interface ProjectCardProps {
  data: {
    id: string;
    img: string;
    title: string;
    description: string;
    tags: string[];
    type: "personal" | "client" | "other";
    details?: string;
    url?: string;
    specialStatus?: string;
  };
  variant: "small" | "large";
  onClick?: () => void;
  buttonType?: "button" | "static" | "none";
  showDivider?: boolean;
}

const ProjectCard: React.FC<ProjectCardProps> = ({
  data,
  variant,
  onClick,
  buttonType = "button",
  showDivider = true
}) => {
  const [isSmallScreen, setIsSmallScreen] = useState(false);
  // Random tilt between -2 and 2 degrees, stable per mount
  const [tilt, setTilt] = useState(0);
  useEffect(() => {
    setTilt(Math.random() * 4 - 2);
  }, []);

  useEffect(() => {
    const checkScreenSize = () => {
      setIsSmallScreen(window.innerWidth < 900);
    };
    checkScreenSize();
    window.addEventListener('resize', checkScreenSize);
    return () => window.removeEventListener('resize', checkScreenSize);
  }, []);

  const handleClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (onClick) {
      onClick();
    } else if (data.url) {
      window.open(data.url, "_blank", "noopener,noreferrer");
    }
  };

  const renderButton = () => {
    if (buttonType === "none") return null;
    if (data.specialStatus && buttonType !== "static") {
      return (
        <div className="special-status">
          <span style={{ color: "var(--primary-color)", fontSize: "1em", fontWeight: "bold" }}>{data.specialStatus}</span>
        </div>
      );
    }
    if (buttonType === "static") {
      return (
        <div className="static-text">
          {data.specialStatus || (variant === "large" ? "View Project" : "Visit Site")}
        </div>
      );
    }
    const commonProps = {
      className: "read-more-button",
      withIcon: true,
      iconDirection: "right" as const,
      size: isSmallScreen ? "s" : (variant === "large" ? "m" : "s") as "s" | "m",
    };
    return (
      <Buttons
        {...commonProps}
        text={isSmallScreen ? "" : variant === "large" ? "Read" : "Visit site"}
        iconName={variant === "large" ? "ArrowRight" : "ArrowSquareOut"}
        withText={!isSmallScreen}
        variant="primary"
        size="s"
      />
    );
  };

  // Add 'no-divider' class if showDivider is false
  const containerClass = `project-container${variant === "small" ? " project-container-small" : ""}${data.specialStatus ? " has-special-status" : ""}${showDivider === false ? " no-divider" : ""}`;

  return (
    <div
      className={containerClass}
      onClick={data.specialStatus ? undefined : handleClick}
      style={{
        transform: `rotate(${tilt}deg)`,
        transition: 'transform 0.25s ease-in-out',
      }}
      onMouseEnter={e => {
        (e.currentTarget as HTMLDivElement).style.transform = 'rotate(0deg)';
      }}
      onMouseLeave={e => {
        (e.currentTarget as HTMLDivElement).style.transform = `rotate(${tilt}deg)`;
      }}
    >
      <img className="project-image" src={data.img} alt={data.title} />

      <div className="project-card">

        <div className="title-details-group">
          <h3>{data.title}</h3>
          <p style={{ opacity: '.6', fontSize: '1.1em' }}>{data.details}</p>
        </div>

        <div className="desc-btn-group">
          {data.description && (
            <p className="description">{data.description}</p>
          )}
          <div className="button-container">
            {renderButton()}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProjectCard;

import React, { useState, useEffect } from 'react';
import '../styles/StackedCard.scss';
import Button from './Buttons';
